// Pull both `res@ == self_@` ensures hypotheses into the proof context.
// Then chain transitivity through `self_@` to derive `r1@ == r2@`, and
// also expose the underlying `Seq<u8>` (`id@`) equality with extensionality
// so the synthetic `det_clone_up_to_view_equal(r1, r2)` is discharged regardless
// of which level of structural / view equality z3 prefers.
assert(r1@ == self_@);
assert(r2@ == self_@);
assert(r1@ == r2@);
assert(r1.id@ == self_.id@);
assert(r2.id@ == self_.id@);
assert(r1.id@ =~= r2.id@);
assert(r1.id@ == r2.id@);
